from dataclasses import dataclass
from typing import List, Dict

class SelfRAGPipeline:
    def __init__(self, current_year: int = 2025):
        self.current_year = current_year

    def score_relevance(self, query: str, documents: List[Dict]) -> float:
        """Average word overlap ratio between query and each document."""
        if not documents:
            return 0.0
        query_words = set(query.lower().split())
        if not query_words:
            return 0.0
        total = 0.0
        for doc in documents:
            doc_words = set(doc['content'].lower().split())
            total += len(query_words & doc_words) / len(query_words)
        return total / len(documents)

    def score_coverage(self, query: str, documents: List[Dict]) -> float:
        """Fraction of query terms covered by at least one document."""
        if not documents:
            return 0.0
        query_words = set(query.lower().split())
        if not query_words:
            return 0.0
        all_doc_words = set()
        for doc in documents:
            all_doc_words.update(doc['content'].lower().split())
        return len(query_words & all_doc_words) / len(query_words)

    def score_freshness(self, documents: List[Dict]) -> float:
        """Average freshness score based on document year."""
        if not documents:
            return 0.0
        total = 0.0
        for doc in documents:
            age = self.current_year - doc['year']
            freshness = max(0, 1 - age / 10)
            total += freshness
        return total / len(documents)

    def decide_action(self, relevance: float, coverage: float, freshness: float) -> str:
        """Decide: 'use', 're_retrieve', or 'parametric'."""
        if relevance >= 0.5 and coverage >= 0.6:
            return 'use'
        elif relevance >= 0.3 or coverage >= 0.4:
            return 're_retrieve'
        else:
            return 'parametric'

    def _doc_relevance(self, query: str, doc: Dict) -> float:
        """Per-document relevance for ranking."""
        query_words = set(query.lower().split())
        doc_words = set(doc['content'].lower().split())
        if not query_words:
            return 0.0
        return len(query_words & doc_words) / len(query_words)

    def process_query(self, query: str, corpus: List[Dict]) -> Dict:
        """Full Self-RAG pipeline: retrieve, score, decide."""
        # Retrieve top-3 by per-document relevance
        scored = [(doc, self._doc_relevance(query, doc)) for doc in corpus]
        scored.sort(key=lambda x: x[1], reverse=True)
        retrieved = [doc for doc, _ in scored[:3]]

        relevance = self.score_relevance(query, retrieved)
        coverage = self.score_coverage(query, retrieved)
        freshness = self.score_freshness(retrieved)
        action = self.decide_action(relevance, coverage, freshness)

        return {
            'action': action,
            'relevance': round(relevance, 3),
            'coverage': round(coverage, 3),
            'freshness': round(freshness, 3),
            'num_retrieved': len(retrieved)
        }

from typing import List, Dict, Optional

class ApprovalGateSystem:
    def __init__(self, auto_approve_levels: List[str] = None):
        self.auto_approve_levels = set(auto_approve_levels or [])
        self.audit_log: List[Dict] = []
        self._next_id = 1

    def submit_action(self, action_name: str, risk_level: str, 
                      metadata: Optional[Dict] = None) -> Dict:
        """Submit an action for approval."""
        action = {
            'id': self._next_id,
            'action': action_name,
            'risk_level': risk_level,
            'status': 'approved' if risk_level in self.auto_approve_levels else 'pending',
            'metadata': metadata if metadata is not None else {}
        }
        self._next_id += 1
        self.audit_log.append(action)
        return action

    def approve(self, action_id: int, approver: str = 'human') -> bool:
        """Approve a pending action."""
        for action in self.audit_log:
            if action['id'] == action_id:
                if action['status'] != 'pending':
                    return False
                action['status'] = 'approved'
                action['approved_by'] = approver
                return True
        return False

    def reject(self, action_id: int, reason: str = '', 
               approver: str = 'human') -> bool:
        """Reject a pending action."""
        for action in self.audit_log:
            if action['id'] == action_id:
                if action['status'] != 'pending':
                    return False
                action['status'] = 'rejected'
                action['rejected_by'] = approver
                action['rejection_reason'] = reason
                return True
        return False

    def get_pending(self) -> List[Dict]:
        """Get all pending actions."""
        return [a for a in self.audit_log if a['status'] == 'pending']

    def get_stats(self) -> Dict:
        """Get approval statistics."""
        stats = {'total': 0, 'approved': 0, 'rejected': 0, 'pending': 0}
        for action in self.audit_log:
            stats['total'] += 1
            stats[action['status']] += 1
        return stats

from typing import List, Dict, Tuple

class MiniResearchAgent:
    def __init__(self, sources: Dict[str, List[Dict]]):
        """sources: {'source_name': [{'content': str, 'credibility': float}, ...]}"""
        self.sources = sources

    def decompose_query(self, query: str) -> List[str]:
        """Decompose query into sub-queries."""
        sub_queries = [query]  # Always include original
        # Split on ' and ' (case-insensitive)
        parts = []
        lower_q = query.lower()
        # Find all occurrences of ' and ' and split
        import re
        segments = re.split(r'\s+and\s+', query, flags=re.IGNORECASE)
        if len(segments) > 1:
            for seg in segments:
                seg = seg.strip()
                if seg and seg != query:
                    sub_queries.append(seg)
        # Deduplicate preserving order
        seen = set()
        unique = []
        for sq in sub_queries:
            if sq not in seen:
                seen.add(sq)
                unique.append(sq)
        return unique

    def search_source(self, sub_query: str, source_name: str) -> List[Dict]:
        """Search a single source."""
        if source_name not in self.sources:
            return []
        query_words = {w.lower() for w in sub_query.split() if len(w) > 2}
        results = []
        for doc in self.sources[source_name]:
            doc_words = set(doc['content'].lower().split())
            if query_words & doc_words:  # At least one match
                results.append(doc)
        results.sort(key=lambda d: d['credibility'], reverse=True)
        return results

    def search_all(self, sub_queries: List[str]) -> List[Tuple[Dict, str]]:
        """Search all sources for all sub-queries."""
        all_results = []
        for sq in sub_queries:
            for source_name in self.sources:
                docs = self.search_source(sq, source_name)
                for doc in docs:
                    all_results.append((doc, source_name))
        return all_results

    def extract_and_verify(self, search_results: List[Tuple[Dict, str]]) -> List[Dict]:
        """Extract claims and cross-reference."""
        claims = []
        for doc, source_name in search_results:
            claims.append({
                'text': doc['content'],
                'source': source_name,
                'credibility': doc['credibility'],
                'corroborated': False
            })

        # Cross-reference: check if claims from different sources share words
        for i, claim in enumerate(claims):
            words_i = {w.lower() for w in claim['text'].split() if len(w) > 3}
            for j, other in enumerate(claims):
                if i == j or claim['source'] == other['source']:
                    continue
                words_j = {w.lower() for w in other['text'].split() if len(w) > 3}
                if len(words_i & words_j) >= 2:
                    claim['corroborated'] = True
                    break

        return claims

    def synthesize(self, query: str, claims: List[Dict]) -> Dict:
        """Produce final report."""
        num_claims = len(claims)
        num_corroborated = sum(1 for c in claims if c['corroborated'])
        confidence = round(num_corroborated / num_claims, 3) if num_claims > 0 else 0.0

        sources_used = sorted(set(c['source'] for c in claims))

        sorted_claims = sorted(claims, key=lambda c: c['credibility'], reverse=True)
        top_claims = [
            {'text': c['text'], 'source': c['source'], 'credibility': c['credibility']}
            for c in sorted_claims[:3]
        ]

        return {
            'query': query,
            'num_claims': num_claims,
            'num_corroborated': num_corroborated,
            'confidence': confidence,
            'sources_used': sources_used,
            'top_claims': top_claims
        }

    def research(self, query: str) -> Dict:
        """Full research pipeline."""
        sub_queries = self.decompose_query(query)
        results = self.search_all(sub_queries)
        claims = self.extract_and_verify(results)
        return self.synthesize(query, claims)
